import axios from "axios";
import * as Consts from "@/common/Consts";
import * as LogUtil from '@/common/LogUtil';

const uploadFileList = (option, fileUploadProgressCallback) => {
    let formData = new FormData();
    formData.append('DIR_PATH', option.DIR_PATH);
    for (var i = 0; i < option.FILE_LIST.length; i++) {
      formData.append('FILE_LIST[' + i + ']', option.FILE_LIST[i]);
    }

    return axios.post(Consts.SERVER_URL + "/api/multiparty/uploadFileList",
      formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        },
        onUploadProgress: function(progressEvent) {
          // LogUtil.debug('uploadFileList(): onUploadProgress(): ', parseInt(Math.round((progressEvent.loaded * 100) / progressEvent.total)));
          if(progressEvent.loaded != null && progressEvent.loaded>0) {
            fileUploadProgressCallback({
              loaded: progressEvent.loaded,
              total: progressEvent.total
            });
          }
        }.bind(this)
      }
    );
};

const uploadFile = option => {
    let formData = new FormData();
    formData.append('DIR_PATH', option.DIR_PATH);
    formData.append('FILE_NAME', option.FILE_NAME);
    formData.append('file', option.file);

    return axios.post(Consts.SERVER_URL + "/api/multiparty/uploadFile",
        formData, {
            headers: {
                'Content-Type': 'multipart/form-data'
            },
            onUploadProgress: function(progressEvent) {
                LogUtil.debug('uploadFile(): onUploadProgress(): ', parseInt(Math.round((progressEvent.loaded * 100) / progressEvent.total)));
            }.bind(this)
        }
    );
};

const deleteFile = option => {
    return axios.post(Consts.SERVER_URL + "/api/multiparty/deleteFile", option);
};

const deleteFileList = option => {
    return axios.post(Consts.SERVER_URL + "/api/multiparty/deleteFileList", option);
};

export { uploadFile, uploadFileList, deleteFile, deleteFileList };