<template>
    <v-container>
        <PagePath />
        <div class="content">
            <div class="update_wrap">
                <h4>소프트웨어 업데이트</h4>
                <div>
                    <dl>
                        <dt>현재 소프트웨어 버전</dt>
                        <dd>{{ `v${version}` }}</dd>
                    </dl>
                    <dl>
                        <dt>업데이트 할 소프트웨어 올리기</dt>
                        <dd>
                            <!-- <input type="file" v-model="selectedFile"/> -->
                            <v-file-input 
                              v-model="selectedFile"
                              @change="doChangeFile()"
                              outlined
                              placeholder="S/W 업데이트 파일을 업로드해 주세요"
                              hide-details />
                        </dd>
                    </dl>
                    <div class="progressbar">
                        <v-progress-linear v-model="fileUploadProgress.loaded" color="#2a85ff" height="15">
                            <!-- <strong>{{ Math.ceil(knowledge) }}%</strong> -->
                        </v-progress-linear>
                    </div>
                </div>
            </div>
            <div class="btn_area">
                <!-- <v-btn elevation="3" color="primary" @click="popupUpdateView(true, false)"> 업데이트 </v-btn> -->
                <v-btn elevation="3" color="primary" @click="doUploadFileList"> 업데이트 </v-btn>
            </div>
        </div>
        <UpdateConfirmPopup v-if="isUpdatePopupOpen" :defaultView="isUpdateDefault" @popupClose="popupUpdateView" />

        <AlertModal :params="alertModalParams"></AlertModal>
    </v-container>
</template>

<script>
import PagePath from '@/components/widget/PagePath';
import UpdateConfirmPopup from '@/components/popup/common/UpdateConfirm';

import * as DateUtil from "@/common/DateUtil";
import * as LogUtil from "@/common/LogUtil";

import AlertModal from '@/components/modal/AlertModal';

import * as FileUploader from "@/rest/FileUploader";

export default {
    components: {
      PagePath,
      UpdateConfirmPopup,
      AlertModal
    },
    data: () => ({
      alertModalParams: { isOpened: false, title: '', message: ''},

      version: '1.4.2',
      knowledge: 33,
      isUpdatePopupOpen: false,
      isUpdateDefault: false,

      selectedFile: null,
      isFileUploadPending: false, 
      fileUploadProgress: { loaded: 0, total: 0 },
    }),
    methods: {
      popupUpdateView(view, succecs) {
        this.isUpdatePopupOpen = view;
        this.isUpdateDefault = succecs;
      },
      doChangeFile() {
        // LogUtil.debug("CheckUpdate: doChangeFile(): this.selectedFile=", this.selectedFile);
        console.log("CheckUpdate: doChangeFile(): this.selectedFile=", this.selectedFile);
      },
      doUploadFileList() {
        // LogUtil.debug('uploadFileList(): this.vars.A_FILE=', this.vars.A_FILE);
        // LogUtil.debug('uploadFileList(): this.vars.R_FILE_LIST=', this.vars.R_FILE_LIST);

        this.isFileUploadPending = true;
        this.fileUploadProgress = { loaded: 0, total: 0 };

        let currentDate = DateUtil.getCurrentDate();

        let fileUploadOption = {
          DIR_PATH:  `/update/${currentDate.substring(0,4)}/${currentDate.substring(5,7)}/${currentDate.substring(8,10)}`,
          FILE_LIST: []
        };

        if(this.selectedFile) {
          fileUploadOption.FILE_LIST.push(this.selectedFile);
        }
        
        FileUploader.uploadFileList(fileUploadOption, (event)=>{
          LogUtil.debug('CheckUpdate: doUploadFileList(): event=', event);
          this.fileUploadProgress.loaded = parseInt(Math.round((event.loaded * 100) / event.total));
          this.fileUploadProgress.total  = 100;
        }).then(() => {
          // LogUtil.debug("uploadFileList(): res.data=", res.data);
        }).finally(()=>{
          this.isFileUploadPending = false;
        });
      },
    },
};
</script>

<style lang="scss" scoped>
.content {
    text-align: center;
    .update_wrap {
        width: 800px;
        border: 1px solid $color-main03;
        border-radius: 10px;
        margin: 47px auto 0;
        h4 {
            @include centerAlign();
            height: 61px;
            border-bottom: 1px solid $color-main03;
            font: {
                size: 20px;
            }
        }
        & > div {
            padding: 34px 50px;
            text-align: left;
            dl {
                @include hCenterAlign();
                width: 100%;
                & + dl {
                    margin-top: 17px;
                }
                font: {
                    weight: 500;
                    size: 18px;
                }
                color: $color-main02;
                dt {
                    width: 300px;
                }
                dd {
                    width: calc(100% - 300px);
                    text-align: right;
                    input[type='file'] {
                        padding: 5px;
                        border: 1px solid #ccc;
                        border-radius: 8px;
                    }
                }
            }
            .progressbar {
                overflow: hidden;
                margin-top: 40px;
                border-radius: 10px;
            }
        }
    }
    .btn_area {
        @include centerAlign();
        width: 100%;
        margin-top: 54px;
        button {
            width: 200px;
            height: 55px;
            font: {
                size: 25px;
            }
        }
    }
}
</style>
